import{_ as a,o,c as t,a2 as r}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"Domains & SSL","description":"","frontmatter":{},"headers":[],"relativePath":"app/domains.md","filePath":"app/domains.md"}'),i={name:"app/domains.md"};function n(s,e,d,l,c,m){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="domains-ssl" tabindex="-1">Domains &amp; SSL <a class="header-anchor" href="#domains-ssl" aria-label="Permalink to &quot;Domains &amp; SSL&quot;">​</a></h1><p>Domains connect a custom hostname to one of your project&#39;s environments. Traefik routes incoming requests by hostname and issues TLS certificates automatically, so every domain is served over HTTPS without manual certificate handling.</p><h2 id="how-domains-map-to-your-config" tabindex="-1">How domains map to your config <a class="header-anchor" href="#how-domains-map-to-your-config" aria-label="Permalink to &quot;How domains map to your config&quot;">​</a></h2><p>A domain is attached to a <strong>routing placeholder</strong> rather than directly to a container. In <code>.tragwerk/config.xml</code> your <a href="/config/routes">routes</a> reference placeholders like <code>{default}</code>, <code>{frontend}</code> or <code>{api}</code>; a domain you add here fills the matching placeholder. This keeps the XML portable while the concrete hostnames live in the WebUI.</p><h2 id="add-a-domain" tabindex="-1">Add a domain <a class="header-anchor" href="#add-a-domain" aria-label="Permalink to &quot;Add a domain&quot;">​</a></h2><ol><li>Open <strong>Domains</strong> and click <strong>Add domain</strong>.</li><li>Enter the <strong>Domain</strong> — hostname only, without <code>https://</code> (e.g. <code>shop.my-company.com</code>).</li><li>Optionally enable <strong>Wildcard domain</strong>. With a wildcard, each environment gets an auto-derived subdomain (e.g. <code>feature-x.preview.my-company.com</code>) as long as no explicit domain is assigned to the same placeholder.</li><li>Set the <strong>Target placeholder</strong> (defaults to <code>default</code>) to the placeholder from your config, such as <code>{default}</code>.</li><li>Click <strong>Add domain</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">DNS</p><p>Point a CNAME or A record for the hostname at your server. Once DNS resolves, Traefik requests a Let&#39;s Encrypt certificate automatically — no extra steps.</p></div><h2 id="set-the-primary-domain" tabindex="-1">Set the primary domain <a class="header-anchor" href="#set-the-primary-domain" aria-label="Permalink to &quot;Set the primary domain&quot;">​</a></h2><p>Exactly <strong>one</strong> primary domain is allowed per project. It is used for absolute links and redirects. In the Domains table, click <strong>Set as primary</strong> on the domain you want; the <strong>Primary</strong> badge moves to it.</p><h2 id="delete-a-domain" tabindex="-1">Delete a domain <a class="header-anchor" href="#delete-a-domain" aria-label="Permalink to &quot;Delete a domain&quot;">​</a></h2><p>Click the trash icon next to a domain and confirm. The hostname stops being routed to the project. If you remove the primary domain, another domain is promoted to primary automatically.</p><h2 id="automatic-ssl" tabindex="-1">Automatic SSL <a class="header-anchor" href="#automatic-ssl" aria-label="Permalink to &quot;Automatic SSL&quot;">​</a></h2><p>TLS is handled by <strong>Traefik</strong> with <strong>Let&#39;s Encrypt</strong>. Certificates are issued and renewed automatically for every domain that resolves to the server; you do not upload or manage certificates yourself.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/config/routes">Routes configuration</a></li><li><a href="/app/environments">Environments</a></li><li><a href="/self-hosting/architecture-on-host">Architecture on the host</a></li></ul>',15)])])}const u=a(i,[["render",n]]);export{p as __pageData,u as default};
